-- Jadval tuzilmasini faqat u mavjud bo'lmasa yaratish
CREATE TABLE IF NOT EXISTS `sms_orders` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` bigint(20) NOT NULL,
  `number` varchar(30) NOT NULL,
  `hash_code` varchar(100) NOT NULL,
  `pass` varchar(60) DEFAULT NULL,
  `sms_code` int(11) DEFAULT NULL,
  `country` varchar(10) NOT NULL,
  `price` int(11) NOT NULL,
  `status` varchar(20) DEFAULT 'waiting',
  `created_at` datetime DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

-- Yangi ma'lumotlarni qo'shish
-- Eslatma: 'id' ustuni avtomatik ko'paygani uchun uni INSERT'dan olib tashladik, 
-- shunda bazadagi eski ID'lar bilan to'qnashuv sodir bo'lmaydi.

